import React from 'react';
import { Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

// Weather condition emoji mapper
const getWeatherEmoji = (condition: string): string => {
  const conditionLower = condition.toLowerCase();
  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
  if (conditionLower.includes('cloud')) return '☁️';
  if (conditionLower.includes('rain')) return '🌧️';
  if (conditionLower.includes('snow')) return '❄️';
  if (conditionLower.includes('wind')) return '💨';
  if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
  if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
  return '🌤️';
};

export default function GeneratedComponent(props: Props) {
  const { city, temperature, condition, humidity, windSpeed, unit, forecast } = props;

  return (
    <div style={{
      maxWidth: '100%',
      padding: 'var(--ggui-spacing-4, 16px)',
    }}>
      <Card padding={24} shadow="md">
        <Stack direction="vertical" gap={24}>
          {/* Header with city name */}
          <div>
            <Text variant="h2" color="var(--ggui-color-primary-900, #0c4a6e)">
              {city}
            </Text>
          </div>

          {/* Current weather section */}
          <Stack direction="horizontal" align="center" gap={32} justify="start">
            {/* Weather emoji and temp */}
            <div style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              gap: 'var(--ggui-spacing-2, 8px)',
            }}>
              <div style={{
                fontSize: '64px',
                lineHeight: '1',
              }}>
                {getWeatherEmoji(condition)}
              </div>
              <div style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-primary-600, #0284c7)',
              }}>
                {Math.round(temperature)}°{unit}
              </div>
            </div>

            {/* Condition and details */}
            <Stack direction="vertical" gap={16} align="start">
              <Text variant="h3" color="var(--ggui-color-neutral-900, #111827)">
                {condition}
              </Text>

              {/* Humidity and Wind Info */}
              <Stack direction="vertical" gap={8}>
                <Row gap={16} align="center">
                  <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">
                    💧 Humidity:
                  </Text>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">
                    {humidity}%
                  </Text>
                </Row>
                <Row gap={16} align="center">
                  <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">
                    💨 Wind:
                  </Text>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">
                    {windSpeed} {unit === 'F' ? 'mph' : 'km/h'}
                  </Text>
                </Row>
              </Stack>
            </Stack>
          </Stack>

          {/* Divider */}
          <div style={{
            height: '1px',
            backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
          }} />

          {/* 5-day forecast */}
          <div>
            <Text variant="label" color="var(--ggui-color-neutral-900, #111827)" weight="semibold">
              5-Day Forecast
            </Text>
            <Stack
              direction="horizontal"
              gap={12}
              align="stretch"
              wrap={true}
              style={{
                marginTop: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              {forecast.map((day, index) => (
                <div
                  key={index}
                  style={{
                    flex: '0 1 calc(20% - 10px)',
                    minWidth: '80px',
                    padding: 'var(--ggui-spacing-2, 8px)',
                    backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    gap: 'var(--ggui-spacing-1, 4px)',
                  }}
                >
                  <Text variant="caption" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">
                    {day.day}
                  </Text>
                  <div style={{ fontSize: '28px', lineHeight: '1' }}>
                    {day.icon}
                  </div>
                  <div style={{
                    display: 'flex',
                    gap: 'var(--ggui-spacing-1, 4px)',
                    alignItems: 'center',
                  }}>
                    <Text variant="caption" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">
                      {Math.round(day.high)}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                      {Math.round(day.low)}°
                    </Text>
                  </div>
                </div>
              ))}
            </Stack>
          </div>
        </Stack>
      </Card>
    </div>
  );
}
